+function buildPreparedCliRunContext(params: {
+  provider: "claude-cli" | "codex-cli";
+  model: string;
+  runId: string;
+  prompt?: string;
+  backend?: Partial<PreparedCliRunContext["preparedBackend"]["backend"]>;
+}): PreparedCliRunContext {
+  const baseBackend =
+    params.provider === "claude-cli"
+      ? {
+          command: "claude",
+          args: ["-p", "--output-format", "stream-json"],
+          output: "jsonl" as const,
+          input: "stdin" as const,
+          modelArg: "--model",
+          systemPromptArg: "--append-system-prompt",
+          systemPromptWhen: "first" as const,
+          serialize: true,
+        }
+      : {
+          command: "codex",
+          args: ["exec", "--json"],
+          resumeArgs: ["exec", "resume", "{sessionId}", "--json"],
+          output: "text" as const,
+          input: "arg" as const,
+          modelArg: "--model",
+          sessionMode: "existing" as const,
+          serialize: true,
+        };
+  const backend = { ...baseBackend, ...params.backend };
+  return {
+    params: {
+      sessionId: "s1",
+      sessionFile: "/tmp/session.jsonl",
+      workspaceDir: "/tmp",
+      prompt: params.prompt ?? "hi",
+      provider: params.provider,
+      model: params.model,
+      timeoutMs: 1_000,
+      runId: params.runId,
+    },
+    started: Date.now(),
+    workspaceDir: "/tmp",
+    backendResolved: {
+      id: params.provider,
+      config: backend,
+      bundleMcp: params.provider === "claude-cli",
+      pluginId: params.provider === "claude-cli" ? "anthropic" : "openai",
+    },
+    preparedBackend: {
+      backend,
+      env: {},
+    },
+    reusableCliSession: {},
+    modelId: params.model,
+    normalizedModel: params.model,
+    systemPrompt: "You are a helpful assistant.",
+    systemPromptReport: {} as PreparedCliRunContext["systemPromptReport"],
+    bootstrapPromptWarningLines: [],
+  };
+}
+
